function renderDetail(e,a){var t=window.formatDate(e.published_at);a.innerHTML=`
        <article class="news-detail">
            <time datetime="${e.published_at}" class="news-detail__date">${t}</time>
            <h1 class="news-detail__title">${window.escapeHtml(e.title)}</h1>
            ${e.image_url?`<img src="${e.image_url}" alt="${window.escapeHtml(e.title)}" class="news-detail__image">`:""}
            <div class="news-detail__content">${e.content}</div>
            <a href="/news.html" class="news-detail__back-link">← Все новости</a>
        </article>
    `}document.addEventListener("DOMContentLoaded",async()=>{var a=document.getElementById("news-detail-container");if(a){var e=window.location.pathname.split("/").pop();if(e)try{var t=await fetch("/api/news/"+e);if(!t.ok)throw new Error("Новость не найдена");renderDetail(await t.json(),a)}catch(e){console.error(e),a.innerHTML=`<p class="error-message">${e.message}</p>`}else a.innerHTML='<p class="error-message">Новость не найдена</p>'}});